Script.script:
WayFinder = WayFinder or MundronClassMethods:new{
  _name="WayFinder",
  _shortname = "WS",
  _module = "Wegeskript",
  _version="1.1.0",
  _fixed_version={MundronClassMethods="1.1.0"},
  config = {no_save=true, load_once=true},
  files = {
    profile = {
      portals = {},
      run_end_action = ""
    },
    game = {
      nodes = {},
      edges = {},
      gags = {}
    }
  },
  data = {},
  enum = {condition={"hp", "sp", "allowed_woldd", "forbidden_world"},
  portal={"all", "enabled", "missing"}}
}

function WayFinder:init()
  local nord, sued = {"nord", "n"}, {"sued", "s"}
  local ost, west = {"ost", "o"}, {"west", "w"}
  local oben, unten = {"ob", "ob"}, {"unt", "u"}
  local empty = {"", ""}

  local aliases = {}

  local save_dirs = function(x, y, z)
    if x == empty and y == empty and z == empty then
      return
    end
    local long, short = f"{y[1]}{x[1]}{z[1]}en", f"{y[2]}{x[2]}{z[2]}"
    aliases[long] = long
    if z == empty or (x == empty and y == empty) then
      aliases[long] = short
      aliases[short] = short
    end
  end

  for _, x in pairs({ost, empty, west}) do
    for _, y in pairs({nord, empty, sued}) do
      for _, z in pairs({oben, empty, unten}) do 
        save_dirs(x, y, z)
      end
    end
  end
  aliases["raus"] = "raus"

  self:assert(len(aliases) == 37, f"Wrong amount of aliases. Created {len(aliases)}/37")
  self.data.aliases = aliases

  return true
end

function WayFinder:show_recording() local recording = table.get(self.data, "recording")
if not recording then self:warn("Es gibt gerade keine aktive Wegaufzeichnung!") return end
self:display_edge(recording) end

function WayFinder:del_steps(number) local path = table.get(self.data, "recording.path")
if number < 0 then self:warn(f"Die Anzahl {number} ist nicht zulaessig.") return elseif not path then self:warn("Es gibt gerade keine aktive Wegaufzeichnung!") return elseif len(path) == 0 then self:warn("Die Wegaufzeichnung hat gar keine Schritte mehr! Abbruch!") self:abort() return elseif len(path) == 1 then self:warn("Du kannst den letzten Eintrag, den Anfangsknoten, nicht loeschen. Falls du das willst, dann breche mit #WAabort ab.") return end
local last_step = path[len(path)] if last_step.type == "#dopath" then local size = len(last_step.substeps) if number > size then self:warn(f"Es ist unzulaessig mehr Schritte ({number}) zu entfernen als das letzte #dopath besitzt ({size}).") return elseif number == size then table.remove(path, len(path)) self:info(f"Der letzte Schritt vom Typ {last_step.type} wurde entfernt.") else local new_substeps = {} for _=1,number do table.remove(last_step.substeps, len(last_step.substeps)) end self:info(f"Die letzten {number} Schritte von #dopath wurden entfernt") end elseif number > 1 then self:warn(f"Der letzte Schritt ist vom Typ {last_step.type} und muss mit der Anzahl 1 komplett geloescht werden.") return else table.remove(path, len(path)) self:info(f"Der letzte Schritt vom Typ {last_step.type} wurde entfernt.") end end

function WayFinder:clean_trigger_and_timer() local run = self.data.last_run if not run then self:log("No run from which triggers/timers can be cleaned") return end table.set(run, {"blocker", "trigger_ids"}, nil) table.apply(run.timer_ids or {}, killTimer) self:log("Kill timers:") self:log(len(run.timer_ids)>0 and run.timer_ids or "Keine vorhanden") run.timer_ids = {}
table.apply(run.trigger_names or {}, disableTrigger) self:log("Kill named triggers:") self:log(len(run.trigger_names)>0 and run.trigger_names or "Keine vorhanden") run.trigger_names = {}
self:kill_all_trigger() end
